//! Launch Interceptor Program — DECIDE (Knight & Leveson, 1986).

use crate::types::{DecideInput, DecideOutput};

const PI: f64 = 3.1415926535;

/// Compare two reals using six significant digits (per specification).
pub fn realcompare(a: f64, b: f64) -> &'static str {
    let ra = round_to_6_significant_digits(a);
    let rb = round_to_6_significant_digits(b);
    if ra == rb {
        "EQ"
    } else if ra < rb {
        "LT"
    } else {
        "GT"
    }
}

fn round_to_6_significant_digits(x: f64) -> f64 {
    if !x.is_finite() {
        return x;
    }
    if x == 0.0 {
        return 0.0;
    }
    let neg = x < 0.0;
    let ax = x.abs();
    let exp = ax.log10().floor();
    let scale = 10_f64.powf(5.0 - exp);
    let r = (ax * scale).round();
    if r == 0.0 {
        return 0.0;
    }
    let val = r / scale;
    if neg {
        -val
    } else {
        val
    }
}

fn distance(x0: f64, y0: f64, x1: f64, y1: f64) -> f64 {
    let dx = x1 - x0;
    let dy = y1 - y0;
    (dx * dx + dy * dy).sqrt()
}

fn triangle_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    ((x2 - x1) * (y3 - y1) - (x3 - x1) * (y2 - y1)).abs() * 0.5
}

/// Quadrant index 0..=3 for I..IV per spec (priority on axes).
fn quadrant(x: f64, y: f64) -> usize {
    let xpos = realcompare(x, 0.0) == "GT";
    let xneg = realcompare(x, 0.0) == "LT";
    let xzero = realcompare(x, 0.0) == "EQ";
    let ypos = realcompare(y, 0.0) == "GT";
    let yneg = realcompare(y, 0.0) == "LT";
    let yzero = realcompare(y, 0.0) == "EQ";

    if xzero && yzero {
        0
    } else if xneg && yzero {
        1
    } else if xzero && yneg {
        2
    } else if xpos && yzero {
        0
    } else if xpos && ypos {
        0
    } else if xneg && ypos {
        1
    } else if xneg && yneg {
        2
    } else if xpos && yneg {
        3
    } else if xzero && ypos {
        0
    } else {
        0
    }
}

/// Smallest circle radius covering three non-degenerate or collinear points.
fn min_circle_radius_three(ax: f64, ay: f64, bx: f64, by: f64, cx: f64, cy: f64) -> f64 {
    let d_ab = distance(ax, ay, bx, by);
    let d_bc = distance(bx, by, cx, cy);
    let d_ca = distance(cx, cy, ax, ay);
    let area = triangle_area(ax, ay, bx, by, cx, cy);

    if realcompare(area, 0.0) == "EQ" {
        return f64::max(f64::max(d_ab, d_bc), d_ca) * 0.5;
    }

    // Angle at B obtuse or right: (A-B)·(C-B) <= 0
    let obtuse_b = {
        let ux = ax - bx;
        let uy = ay - by;
        let vx = cx - bx;
        let vy = cy - by;
        realcompare(ux * vx + uy * vy, 0.0) != "GT"
    };
    let obtuse_a = {
        let ux = bx - ax;
        let uy = by - ay;
        let vx = cx - ax;
        let vy = cy - ay;
        realcompare(ux * vx + uy * vy, 0.0) != "GT"
    };
    let obtuse_c = {
        let ux = ax - cx;
        let uy = ay - cy;
        let vx = bx - cx;
        let vy = by - cy;
        realcompare(ux * vx + uy * vy, 0.0) != "GT"
    };

    if obtuse_b {
        return d_ca * 0.5;
    }
    if obtuse_a {
        return d_bc * 0.5;
    }
    if obtuse_c {
        return d_ab * 0.5;
    }

    (d_ab * d_bc * d_ca) / (4.0 * area)
}

fn angle_at_vertex(
    px: f64,
    py: f64,
    vx: f64,
    vy: f64,
    qx: f64,
    qy: f64,
) -> Option<f64> {
    let ux = px - vx;
    let uy = py - vy;
    let vx2 = qx - vx;
    let vy2 = qy - vy;
    if realcompare(ux * ux + uy * uy, 0.0) == "EQ" || realcompare(vx2 * vx2 + vy2 * vy2, 0.0) == "EQ" {
        return None;
    }
    let nu = (ux * ux + uy * uy).sqrt();
    let nv = (vx2 * vx2 + vy2 * vy2).sqrt();
    let c = (ux * vx2 + uy * vy2) / (nu * nv);
    let c = c.clamp(-1.0, 1.0);
    Some(c.acos())
}

fn point_to_line_distance(px: f64, py: f64, ax: f64, ay: f64, bx: f64, by: f64) -> f64 {
    if realcompare(ax, bx) == "EQ" && realcompare(ay, by) == "EQ" {
        return distance(px, py, ax, ay);
    }
    let num = ((by - ay) * px - (bx - ax) * py + bx * ay - by * ax).abs();
    let den = distance(ax, ay, bx, by);
    num / den
}

fn lic1(input: &DecideInput) -> bool {
    let p = &input.parameters;
    let n = input.numpoints;
    for i in 0..n - 1 {
        let d = distance(input.x[i], input.y[i], input.x[i + 1], input.y[i + 1]);
        if realcompare(d, p.length1) == "GT" {
            return true;
        }
    }
    false
}

fn lic2(input: &DecideInput) -> bool {
    let p = &input.parameters;
    let n = input.numpoints;
    for i in 0..n - 2 {
        let r = min_circle_radius_three(
            input.x[i],
            input.y[i],
            input.x[i + 1],
            input.y[i + 1],
            input.x[i + 2],
            input.y[i + 2],
        );
        if realcompare(r, p.radius1) == "GT" {
            return true;
        }
    }
    false
}

fn lic3(input: &DecideInput) -> bool {
    let p = &input.parameters;
    let n = input.numpoints;
    let low = PI - p.epsilon;
    let high = PI + p.epsilon;
    for i in 0..n - 2 {
        let Some(angle) = angle_at_vertex(
            input.x[i],
            input.y[i],
            input.x[i + 1],
            input.y[i + 1],
            input.x[i + 2],
            input.y[i + 2],
        ) else {
            continue;
        };
        if realcompare(angle, low) == "LT" || realcompare(angle, high) == "GT" {
            return true;
        }
    }
    false
}

fn lic4(input: &DecideInput) -> bool {
    let p = &input.parameters;
    let n = input.numpoints;
    for i in 0..n - 2 {
        let a = triangle_area(
            input.x[i],
            input.y[i],
            input.x[i + 1],
            input.y[i + 1],
            input.x[i + 2],
            input.y[i + 2],
        );
        if realcompare(a, p.area1) == "GT" {
            return true;
        }
    }
    false
}

fn lic5(input: &DecideInput) -> bool {
    let p = &input.parameters;
    let n = input.numpoints;
    let q = p.q_pts;
    let quads = p.quads;
    for start in 0..=n.saturating_sub(q) {
        let mut seen = [false; 4];
        let mut count = 0usize;
        for j in 0..q {
            let idx = start + j;
            let qd = quadrant(input.x[idx], input.y[idx]);
            if !seen[qd] {
                seen[qd] = true;
                count += 1;
            }
        }
        if count > quads {
            return true;
        }
    }
    false
}

fn lic6(input: &DecideInput) -> bool {
    let n = input.numpoints;
    for i in 0..n - 1 {
        let j = i + 1;
        let dx = input.x[j] - input.x[i];
        if realcompare(dx, 0.0) == "LT" {
            return true;
        }
    }
    false
}

fn lic7(input: &DecideInput) -> bool {
    let p = &input.parameters;
    let n = input.numpoints;
    if n < 3 {
        return false;
    }
    let np = p.n_pts;
    for start in 0..=n - np {
        let ax = input.x[start];
        let ay = input.y[start];
        let bx = input.x[start + np - 1];
        let by = input.y[start + np - 1];
        for k in 1..np - 1 {
            let d = point_to_line_distance(input.x[start + k], input.y[start + k], ax, ay, bx, by);
            if realcompare(d, p.dist) == "GT" {
                return true;
            }
        }
    }
    false
}

fn lic8(input: &DecideInput) -> bool {
    let p = &input.parameters;
    let n = input.numpoints;
    if n < 3 {
        return false;
    }
    let k = p.k_pts;
    for i in 0..n {
        let j = i + k + 1;
        if j >= n {
            break;
        }
        let d = distance(input.x[i], input.y[i], input.x[j], input.y[j]);
        if realcompare(d, p.length1) == "GT" {
            return true;
        }
    }
    false
}

fn lic9(input: &DecideInput) -> bool {
    let p = &input.parameters;
    let n = input.numpoints;
    if n < 5 {
        return false;
    }
    let a = p.a_pts;
    let b = p.b_pts;
    for i in 0..n {
        let i2 = i + a + 1;
        let i3 = i2 + b + 1;
        if i3 >= n {
            break;
        }
        let r = min_circle_radius_three(
            input.x[i],
            input.y[i],
            input.x[i2],
            input.y[i2],
            input.x[i3],
            input.y[i3],
        );
        if realcompare(r, p.radius1) == "GT" {
            return true;
        }
    }
    false
}

fn lic10(input: &DecideInput) -> bool {
    let p = &input.parameters;
    let n = input.numpoints;
    if n < 5 {
        return false;
    }
    let c = p.c_pts;
    let d = p.d_pts;
    let low = PI - p.epsilon;
    let high = PI + p.epsilon;
    for i in 0..n {
        let i2 = i + c + 1;
        let i3 = i2 + d + 1;
        if i3 >= n {
            break;
        }
        let Some(angle) = angle_at_vertex(
            input.x[i],
            input.y[i],
            input.x[i2],
            input.y[i2],
            input.x[i3],
            input.y[i3],
        ) else {
            continue;
        };
        if realcompare(angle, low) == "LT" || realcompare(angle, high) == "GT" {
            return true;
        }
    }
    false
}

fn lic11(input: &DecideInput) -> bool {
    let p = &input.parameters;
    let n = input.numpoints;
    if n < 5 {
        return false;
    }
    let e = p.e_pts;
    let f = p.f_pts;
    for i in 0..n {
        let i2 = i + e + 1;
        let i3 = i2 + f + 1;
        if i3 >= n {
            break;
        }
        let a = triangle_area(
            input.x[i],
            input.y[i],
            input.x[i2],
            input.y[i2],
            input.x[i3],
            input.y[i3],
        );
        if realcompare(a, p.area1) == "GT" {
            return true;
        }
    }
    false
}

fn lic12(input: &DecideInput) -> bool {
    let p = &input.parameters;
    let n = input.numpoints;
    if n < 3 {
        return false;
    }
    let g = p.g_pts;
    for i in 0..n {
        let j = i + g + 1;
        if j >= n {
            break;
        }
        let dx = input.x[j] - input.x[i];
        if realcompare(dx, 0.0) == "LT" {
            return true;
        }
    }
    false
}

fn lic13(input: &DecideInput) -> bool {
    let p = &input.parameters;
    let n = input.numpoints;
    if n < 3 {
        return false;
    }
    let k = p.k_pts;
    let mut gt = false;
    let mut lt = false;
    for i in 0..n {
        let j = i + k + 1;
        if j >= n {
            break;
        }
        let d = distance(input.x[i], input.y[i], input.x[j], input.y[j]);
        if realcompare(d, p.length1) == "GT" {
            gt = true;
        }
        if realcompare(d, p.length2) == "LT" {
            lt = true;
        }
    }
    gt && lt
}

fn lic14(input: &DecideInput) -> bool {
    let p = &input.parameters;
    let n = input.numpoints;
    if n < 5 {
        return false;
    }
    let a = p.a_pts;
    let b = p.b_pts;
    let mut cannot_r1 = false;
    let mut can_r2 = false;
    for i in 0..n {
        let i2 = i + a + 1;
        let i3 = i2 + b + 1;
        if i3 >= n {
            break;
        }
        let r = min_circle_radius_three(
            input.x[i],
            input.y[i],
            input.x[i2],
            input.y[i2],
            input.x[i3],
            input.y[i3],
        );
        if realcompare(r, p.radius1) == "GT" {
            cannot_r1 = true;
        }
        if realcompare(r, p.radius2) != "GT" {
            can_r2 = true;
        }
    }
    cannot_r1 && can_r2
}

fn lic15(input: &DecideInput) -> bool {
    let p = &input.parameters;
    let n = input.numpoints;
    if n < 5 {
        return false;
    }
    let e = p.e_pts;
    let f = p.f_pts;
    let mut gt_area1 = false;
    let mut lt_area2 = false;
    for i in 0..n {
        let i2 = i + e + 1;
        let i3 = i2 + f + 1;
        if i3 >= n {
            break;
        }
        let a = triangle_area(
            input.x[i],
            input.y[i],
            input.x[i2],
            input.y[i2],
            input.x[i3],
            input.y[i3],
        );
        if realcompare(a, p.area1) == "GT" {
            gt_area1 = true;
        }
        if realcompare(a, p.area2) == "LT" {
            lt_area2 = true;
        }
    }
    gt_area1 && lt_area2
}

fn build_cmv(input: &DecideInput) -> Vec<bool> {
    vec![
        lic1(input),
        lic2(input),
        lic3(input),
        lic4(input),
        lic5(input),
        lic6(input),
        lic7(input),
        lic8(input),
        lic9(input),
        lic10(input),
        lic11(input),
        lic12(input),
        lic13(input),
        lic14(input),
        lic15(input),
    ]
}

fn build_pum(input: &DecideInput, cmv: &[bool]) -> Vec<Vec<bool>> {
    let mut pum = vec![vec![false; 15]; 15];
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                pum[i][j] = input.pum_diag[i];
            } else {
                pum[i][j] = match input.lcm[i][j].as_str() {
                    "NOTUSED" => true,
                    "ANDD" => cmv[i] && cmv[j],
                    "ORR" => cmv[i] || cmv[j],
                    _ => false,
                };
            }
        }
    }
    pum
}

fn build_fuv(pum: &[Vec<bool>]) -> Vec<bool> {
    (0..15)
        .map(|i| {
            let diag_false = !pum[i][i];
            let row_all = (0..15).all(|j| pum[i][j]);
            diag_false || row_all
        })
        .collect()
}

pub fn decide(input: &DecideInput) -> DecideOutput {
    let cmv = build_cmv(input);
    let pum = build_pum(input, &cmv);
    let fuv = build_fuv(&pum);
    let launch = fuv.iter().all(|&v| v);
    DecideOutput {
        cmv,
        pum,
        fuv,
        launch,
    }
}
